
$c-parchment: #f5f0e0;
$c-ink: #2c1810;
$c-gold: #c8a45c;
$c-crimson: #8b3a3a;
$c-forest: #3a5c3a;
$c-slate: #4a5568;
$c-blue: #3a6b8b;
$c-pink: #c06080;
$c-purple: #6b3a8b;

.guild-card {
  width: 100%;
  max-width: 420px;
  background: linear-gradient(180deg, #faf3e0 0%, #f0e8d0 100%);
  border: 2px solid $c-gold;
  box-shadow: 3px 3px 0px rgba(44, 24, 16, 0.15);
  font-family: 'Georgia', serif;
  color: $c-ink;
  font-size: 12px;
  line-height: 1.5;
  margin: 0 auto;
  border-radius: 2px;
}

.card-header {
  background: linear-gradient(180deg, $c-ink 0%, #3d2a1a 100%);
  color: $c-parchment;
  padding: 8px 12px;
  display: flex;
  align-items: center;
  gap: 10px;
  border-bottom: 2px solid $c-gold;
}

.header-rank {
  display: flex;
  align-items: baseline;
  gap: 2px;
  font-size: 1.8rem;
  font-weight: bold;
  color: $c-gold;
}

.rank-star {
  font-size: 1.2rem;
}

.header-info {
  flex: 1;
}

.card-title {
  font-size: 0.95rem;
  margin: 0;
  letter-spacing: 0.08em;
  font-weight: normal;
}

.card-subtitle {
  font-size: 0.65rem;
  color: #c0a88c;
  letter-spacing: 0.05em;
}

.header-stage {
  font-size: 0.75rem;
  padding: 2px 8px;
  border: 1px solid;
  font-weight: bold;
  letter-spacing: 0.1em;
}

.stage-pure {
  color: #7b9cb0;
  border-color: #7b9cb0;
}

.stage-waver {
  color: #c8a060;
  border-color: #c8a060;
}

.stage-fallen {
  color: $c-crimson;
  border-color: $c-crimson;
  text-shadow: 0 0 6px rgba(139, 58, 58, 0.3);
}

/* Bars */
.bars-section {
  padding: 8px 12px 4px;
}

.bar-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 5px;
}

.bar-label {
  width: 52px;
  font-size: 0.7rem;
  text-align: right;
  flex-shrink: 0;
}

.label-danger {
  color: $c-crimson;
}

.bar-track {
  flex: 1;
  height: 10px;
  background: #ddd0b8;
  border: 1px solid #c0a880;
  border-radius: 1px;
  overflow: hidden;
}

.corruption-track {
  background: linear-gradient(90deg, #ddd0b8, #e0c0c0);
}

.arousal-track {
  background: linear-gradient(90deg, #ddd0b8, #e0c0d0);
}

.bar-fill {
  height: 100%;
  transition: width 0.4s ease;
}

.hp-fill {
  background: linear-gradient(90deg, $c-crimson, #cc5555);
}

.mp-fill {
  background: linear-gradient(90deg, $c-blue, #5599cc);
}

.corruption-fill {
  background: linear-gradient(90deg, $c-purple, $c-crimson, #cc3333);
}

.arousal-fill {
  background: linear-gradient(90deg, $c-pink, #e080a0);
}

.bar-value {
  width: 44px;
  font-size: 0.65rem;
  text-align: left;
  color: $c-slate;
}

.value-danger {
  color: $c-crimson;
}

.corruption-section {
  padding: 0 12px 4px;
}

/* Status */
.status-section {
  padding: 2px 12px 6px;
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.status-badge {
  font-size: 0.62rem;
  padding: 1px 6px;
  border: 1px solid;
  color: $c-ink;
}

.status-badge.poison { border-color: #6b8b3a; color: #6b8b3a; }
.status-badge.paralysis { border-color: #c8a040; color: #c8a040; }
.status-badge.aphrodisiac { border-color: #c06080; color: #c06080; }
.status-badge.tentacle_parasite { border-color: $c-purple; color: $c-purple; }
.status-badge.curse { border-color: $c-ink; color: $c-ink; }
.status-badge.charm { border-color: #cc4488; color: #cc4488; }

/* Footer */
.card-footer {
  display: flex;
  justify-content: space-around;
  padding: 6px 12px;
  border-top: 1px solid #d0c8a8;
  background: rgba(200, 164, 92, 0.08);
}

.footer-stat {
  display: flex;
  align-items: center;
  gap: 3px;
  font-size: 0.65rem;
  color: $c-slate;
}

.stat-icon {
  font-size: 0.75rem;
}

@media (max-width: 400px) {
  .guild-card {
    font-size: 11px;
  }
  .bar-label {
    width: 42px;
  }
}
